sp_widget.client_script:
api.controller = function($scope, spUtil) {

	var c = this;

	c.files = [];
	c.submitting = false;

	/* =====================================
       FIELD ERRORS
    ===================================== */

	c.errors = {};

	/* =====================================
       HANDLE FILES
    ===================================== */

	c.handleFiles = function(files) {

		$scope.$apply(function() {

			for (var i = 0; i < files.length; i++) {

				c.files.push({
					name: files[i].name,
					raw: files[i]
				});

			}

		});

	};

	/* =====================================
       REMOVE FILE
    ===================================== */

	c.removeFile = function(index) {

		c.files.splice(index, 1);

	};

	/* =====================================
       VALIDATE FORM
    ===================================== */

	c.validateForm = function() {

		c.errors = {};

		if (!c.data.full_name) {
			c.errors.full_name = "Please fill this field";
		}

		if (!c.data.email) {
			c.errors.email = "Please fill this field";
		}

		if (!c.data.issue_type) {
			c.errors.issue_type = "Please select an issue type";
		}

		if (!c.data.priority) {
			c.errors.priority = "Please select a priority";
		}

		if (!c.data.subject) {
			c.errors.subject = "Please fill this field";
		}

		if (!c.data.description) {
			c.errors.description = "Please fill this field";
		}

		return Object.keys(c.errors).length === 0;

	};

	/* =====================================
       SUBMIT FORM
    ===================================== */

	c.submitRequest = function() {

		/* VALIDATE */
		if (!c.validateForm()) {

			spUtil.addErrorMessage(
				"Please fill all required fields."
			);

			return;
		}

		c.submitting = true;

		// c.data.action = "";

		c.server.get({
			action:"submit_support_request",
			full_name: c.data.full_name,
			email: c.data.email,
			issue_type: c.data.issue_type,
			priority: c.data.priority,
			subject: c.data.subject,
			description: c.data.description
		}).then(function(response) {

			c.submitting = false;

			if (response.data.sys_id) {

				spUtil.addInfoMessage(
					"Support request submitted successfully."
				);

				uploadAttachments(response.data.sys_id);

				clearForm();

			} else {

				spUtil.addErrorMessage(
					"Failed to submit request."
				);

			}

		});

	};

	/* =====================================
       UPLOAD ATTACHMENTS
    ===================================== */

	function uploadAttachments(recordSysId) {

		if (!c.files.length)
			return;

		var formData = new FormData();

		angular.forEach(c.files, function(fileObj) {

			formData.append(
				"attachFile",
				fileObj.raw
			);

		});

		var xhr = new XMLHttpRequest();

		xhr.open(
			"POST",
			"/api/now/attachment/upload" +
			"?table_name=x_sysus_tracenow_support_request" +
			"&table_sys_id=" + recordSysId,
			true
		);

		xhr.setRequestHeader(
			"X-UserToken",
			window.g_ck
		);

		xhr.send(formData);

	}

	/* =====================================
       CLEAR FORM
    ===================================== */

	function clearForm() {

		/* RESET FORM DATA */

		c.data = {};

		/* RESET ERRORS */
		c.errors = {};

		/* RESET FILES */
		c.files = [];

		/* RESET FILE INPUT */
		var fileInput = document.querySelector(
			'.tn-upload-box input[type="file"]'
		);

		if (fileInput) {
			fileInput.value = "";
		}

		/* REFRESH UI */
		$scope.$applyAsync();

	}

};

sp_widget.css:
.tn-page-layout {
    display: flex;
    min-height: 100vh;
   position:relative;
}

.tn-left-sidebar {
   flex-basis: 260px;
  flex-shrink:0;
  height:100%;
  position:sticky;
  top: 0;

}

/* ========================================
   ROOT
======================================== */

.tn-support-page {
    background: #f5f7fb;
    color: #08142b;
    width:100%;
}

/* ========================================
   CONTAINER
======================================== */

.tn-container {
    width: 100%;
    max-width: 1180px;
    margin: 0 auto;
    padding: 0 24px;
}

/* ========================================
   HERO
======================================== */

.tn-hero {
    position: relative;
    overflow: hidden;
    padding: 64px 0 72px;
    background:
        radial-gradient(
            circle at top left,
            rgba(155,192,252,0.45),
            transparent 34%
        ),
        linear-gradient(
            135deg,
            #116AF8 0%,
            #0A50F5 55%,
            #0847DC 100%
        );
}

/* glow */
.tn-hero:before {
    content: "";
    position: absolute;
    width: 620px;
    height: 620px;
    border-radius: 50%;
    background: rgba(255,255,255,0.06);
    top: -280px;
    left: -180px;
    filter: blur(30px);
}

.tn-hero-overlay {
    position: absolute;
    inset: 0;
    background:
        linear-gradient(
            to bottom,
            rgba(255,255,255,0.02),
            rgba(255,255,255,0)
        );
}

/* ========================================
   BRAND
======================================== */

.tn-brand {
    display: flex;
    align-items: center;
    margin-bottom: 56px;
    position: relative;
    z-index: 2;
}

.tn-brand-icon {

    //width: 340px;
    height: auto;

    display: flex;
    align-items: center;

    position: relative;

    transition: all 0.3s ease;
}

.tn-brand-icon svg {

    width: 100%;
    height: auto;

    display: block;

    filter:
        drop-shadow(0 6px 20px rgba(0,0,0,0.18));

    opacity: 0.98;
}

@media screen and (max-width: 768px) {

    .tn-brand {
        margin-bottom: 40px;
    }

    .tn-brand-icon {
        width: 240px;
    }
}

.tn-brand-icon:hover {
    transform: translateY(-2px) scale(1.01);
}

/*.tn-brand-text {
    color: #ffffff;
    font-size: 20px;
    font-weight: 700;
    letter-spacing: -0.3px;
}*/

/* ========================================
   HERO CONTENT
======================================== */

.tn-hero-content {
    position: relative;
    z-index: 2;
    max-width: 760px;
}

.tn-hero-content h1 {
    margin: 0 0 24px;
    color: #ffffff;
    font-size: 74px;
    line-height: 1.02;
    font-weight: 800;
    letter-spacing: -2px;
}

.tn-hero-content p {
    margin: 0;
    color: rgba(255,255,255,0.82);
    font-size: 21px;
    line-height: 1.8;
    max-width: 760px;
}

/* ========================================
   STATS
======================================== */

.tn-stats {
    display: flex;
    gap: 24px;
    margin-top: 52px;
    flex-wrap: wrap;
}

.tn-stat-card {
    width: 220px;
    min-height: 118px;

    padding: 22px 24px;

    border-radius: 20px;

    background: rgba(255,255,255,0.10);

    border: 1px solid rgba(255,255,255,0.16);

    backdrop-filter: blur(10px);

    box-shadow:
        0 10px 30px rgba(0,0,0,0.08);
}

.tn-stat-card h2 {
    margin: 0 0 10px;
    color: #ffffff;
    font-size: 52px;
    line-height: 1;
    font-weight: 800;
    letter-spacing: -2px;
}

.tn-stat-card span {
    color: rgba(255,255,255,0.82);
    font-size: 17px;
    font-weight: 500;
}

/* ========================================
   TOPICS SECTION
======================================== */

.tn-topics-section {
    padding: 70px 0 90px;
}

.tn-section-title {
    margin: 0 0 34px;
    color: #08142b;
    font-size: 42px;
    font-weight: 800;
    letter-spacing: -1px;
}

/* ========================================
   GRID
======================================== */

.tn-topic-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 24px;
}

/* ========================================
   CARD
======================================== */

.tn-topic-card {
    background: #ffffff;

    border-radius: 22px;

    padding: 34px 30px;

    border: 1px solid #e8edf5;

    transition: all 0.25s ease;

    box-shadow:
        0 4px 14px rgba(8,20,43,0.04);
}

.tn-topic-card:hover {
    transform: translateY(-6px);

    box-shadow:
        0 18px 40px rgba(8,20,43,0.10);
}

.tn-topic-icon {
    width: 58px;
    height: 58px;
    border-radius: 18px;

    display: flex;
    align-items: center;
    justify-content: center;

    background: #F4F8FF;

    color: #116AF8;

    font-size: 26px;

    margin-bottom: 28px;
}

.tn-topic-card h3 {
    margin: 0 0 16px;

    color: #08142b;

    font-size: 30px;
    line-height: 1.2;
    font-weight: 700;
    letter-spacing: -0.6px;
}

.tn-topic-card p {
    margin: 0;

    color: #516074;

    font-size: 18px;
    line-height: 1.7;
}

/* ========================================
   RESPONSIVE
======================================== */

@media screen and (max-width: 1100px) {

    .tn-topic-grid {
        grid-template-columns: repeat(2, 1fr);
    }

    .tn-hero-content h1 {
        font-size: 58px;
    }
}

@media screen and (max-width: 768px) {

    .tn-hero {
        padding: 50px 0 60px;
    }

    .tn-brand {
        margin-bottom: 40px;
    }

    .tn-hero-content h1 {
        font-size: 46px;
    }

    .tn-hero-content p {
        font-size: 18px;
        line-height: 1.7;
    }

    .tn-stats {
        flex-direction: column;
    }

    .tn-stat-card {
        width: 100%;
    }

    .tn-topic-grid {
        grid-template-columns: 1fr;
    }

    .tn-section-title {
        font-size: 34px;
    }

    .tn-topic-card h3 {
        font-size: 26px;
    }
}

/* ========================================
   SUPPORT FORM SECTION
======================================== */

.tn-support-form-section {
    padding: 0 0 90px;
}

/* ========================================
   LAYOUT
======================================== */

.tn-form-layout {
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 30px;
    align-items: start;
}

/* ========================================
   FORM CARD
======================================== */

.tn-form-card {
    background: #ffffff;
    border-radius: 22px;
    overflow: hidden;

    border: 1px solid #e5eaf2;

    box-shadow:
        0 10px 30px rgba(15, 23, 42, 0.05);
}

/* ========================================
   HEADER
======================================== */

.tn-form-header {
    background: linear-gradient(
        135deg,
        #116AF8 0%,
        #0A50F5 100%
    );

    padding: 28px 30px;

    display: flex;
    align-items: center;
    gap: 16px;
}

.tn-form-header-icon {
    width: 44px;
    height: 44px;

    border-radius: 14px;

    display: flex;
    align-items: center;
    justify-content: center;

    background: rgba(255,255,255,0.14);

    color: #ffffff;

    font-size: 20px;
}

.tn-form-header h2 {
    margin: 0;
    color: #ffffff;
    font-size: 20px;
    font-weight: 700;
}

/* ========================================
   BODY
======================================== */

.tn-form-body {
    padding: 30px;
}

/* ========================================
   GRID
======================================== */

.tn-form-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 22px;
}

/* ========================================
   FIELD
======================================== */

.tn-field {
    margin-bottom: 22px;
}

.tn-field label {
    display: block;
    margin-bottom: 10px;

    color: #10213a;

    font-size: 14px;
    font-weight: 600;
}

.tn-field label span {
    color: #ff4f67;
}

.tn-field input,
.tn-field select,
.tn-field textarea {
    width: 100%;

    border: 1px solid #cfd8e6;

    background: #ffffff;

    border-radius: 16px;

    padding: 15px 16px;

    font-size: 16px;

    color: #0f172a;

    transition: all 0.2s ease;

    outline: none;

    box-shadow: none;
}

.tn-field textarea {
    resize: none;
    min-height: 170px;
    line-height: 1.7;
}

.tn-field input::placeholder,
.tn-field textarea::placeholder {
    color: #98a2b3;
}

.tn-field input:focus,
.tn-field select:focus,
.tn-field textarea:focus {
    border-color: #116AF8;

    box-shadow: 0 0 0 4px rgba(17,106,248,0.10);
}

/* ========================================
   UPLOAD
======================================== */

.tn-upload-box {
    position: relative;

    border: 1.5px dashed #116AF8;

    background: #F8FBFF;

    border-radius: 18px;

    height: 66px;

    display: flex;
    align-items: center;
    justify-content: center;
    gap: 12px;

    color: #10213a;

    font-size: 15px;
    font-weight: 500;

    cursor: pointer;

    overflow: hidden;
}

.tn-upload-box i {
    color: #116AF8;
    font-size: 20px;
}

.tn-upload-box input {
    position: absolute;
    inset: 0;

    opacity: 0;
    cursor: pointer;
}

.tn-upload-note {
    margin-top: 10px;

    color: #7a869a;

    font-size: 12px;
}
/* ========================================
   UPLOAD CONTENT
======================================== */

.tn-upload-content {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 12px;
}

/* ========================================
   ACTIVE STATE
======================================== */

.tn-upload-box.has-files {
    background: #f0fcf7;
    border-color: #15a46b;
}

/* ========================================
   FILE LIST
======================================== */

.tn-file-list {
    margin-top: 16px;
}

.tn-file-item {
    display: flex;
    align-items: center;
    justify-content: space-between;

    padding: 14px 16px;

    background: #ffffff;

    border: 1px solid #e3e8f1;

    border-radius: 14px;

    margin-bottom: 12px;

    transition: all 0.2s ease;
}

.tn-file-item:hover {
    background: #f8fafc;
}

.tn-file-left {
    display: flex;
    align-items: center;
    gap: 12px;
}

.tn-file-left i {
    color: #116AF8;
    font-size: 18px;
}

.tn-file-name {
    color: #10213a;
    font-size: 14px;
    font-weight: 500;
}

/* ========================================
   REMOVE BUTTON
======================================== */

.tn-remove-file {
    width: 32px;
    height: 32px;

    border: none;
    outline: none;

    border-radius: 10px;

    background: #fff1f1;

    color: #ff4b4b;

    transition: all 0.2s ease;
}

.tn-remove-file:hover {
    background: #ffe1e1;
}
/* ========================================
   BUTTON
======================================== */

.tn-submit-btn {
    width: 100%;
    height: 58px;

    border: none;
    outline: none;

    border-radius: 18px;

    background:
        linear-gradient(
            135deg,
            #116AF8 0%,
            #0A50F5 100%
        );

    color: #ffffff;

    font-size: 18px;
    font-weight: 700;

    display: flex;
    align-items: center;
    justify-content: center;
    gap: 14px;

    transition: all 0.25s ease;

    box-shadow:
        0 12px 24px rgba(17,106,248,0.25);
}

.tn-submit-btn:hover {
    transform: translateY(-2px);

    box-shadow:
        0 16px 30px rgba(17,106,248,0.32);
}

/* ========================================
   RIGHT PANEL
======================================== */

.tn-side-panel {
    display: flex;
    flex-direction: column;
    gap: 22px;
}

/* ========================================
   SIDE CARD
======================================== */

.tn-side-card,
.tn-critical-card {
    background: #ffffff;

    border-radius: 22px;

    padding: 24px;

    border: 1px solid #e7ecf3;

    box-shadow:
        0 8px 24px rgba(15,23,42,0.05);
}

.tn-side-title {
    display: flex;
    align-items: center;
    gap: 12px;

    margin-bottom: 28px;

    color: #08142b;

    font-size: 16px;
    font-weight: 700;
}

.tn-side-title i {
    color: #116AF8;
    font-size: 18px;
}

/* ========================================
   HELP ITEMS
======================================== */

.tn-help-item {
    display: flex;
    gap: 14px;

    margin-bottom: 26px;
}

.tn-help-item:last-child {
    margin-bottom: 0;
}

.tn-help-icon {
    width: 42px;
    height: 42px;

    border-radius: 14px;

    display: flex;
    align-items: center;
    justify-content: center;

    background: #F4F8FF;

    color: #116AF8;

    flex-shrink: 0;
}

.tn-help-item h4 {
    margin: 0 0 6px;

    color: #08142b;

    font-size: 16px;
    font-weight: 700;
}

.tn-help-item p {
    margin: 0;

    color: #667085;

    font-size: 13px;
    line-height: 1.6;
}

/* ========================================
   RESPONSE CARD
======================================== */

.tn-response-card {
    background:
        linear-gradient(
            135deg,
            #116AF8 0%,
            #0A50F5 100%
        );

    border-radius: 22px;

    padding: 24px;

    color: #ffffff;

    box-shadow:
        0 12px 28px rgba(17,106,248,0.28);
}

.tn-response-icon {
    width: 42px;
    height: 42px;

    border-radius: 50%;

    border: 2px solid rgba(255,255,255,0.7);

    display: flex;
    align-items: center;
    justify-content: center;

    margin-bottom: 22px;

    font-size: 20px;
}

.tn-response-card h3 {
    margin: 0 0 14px;

    font-size: 28px;
    line-height: 1.2;
    font-weight: 700;
}

.tn-response-card p {
    margin: 0 0 18px;

    color: rgba(255,255,255,0.88);

    font-size: 15px;
    line-height: 1.8;
}

.tn-response-badge {
    display: flex;
    align-items: center;
    gap: 10px;

    color: #ffffff;

    font-size: 14px;
    font-weight: 500;
}

/* ========================================
   CRITICAL CARD
======================================== */

.tn-critical-card {
    background: #fff8f8;
    border: 1px solid #ffc9c9;
}

.tn-critical-top {
    display: flex;
    align-items: center;
    gap: 14px;

    margin-bottom: 18px;
}

.tn-critical-icon {
    width: 42px;
    height: 42px;

    border-radius: 14px;

    background: #ffe9e9;

    color: #ff3b3b;

    display: flex;
    align-items: center;
    justify-content: center;

    font-size: 18px;
}

.tn-critical-card h3 {
    margin: 0;

    color: #c62828;

    font-size: 18px;
    font-weight: 700;
}

.tn-critical-card p {
    margin: 0 0 18px;

    color: #d32f2f;

    font-size: 15px;
    line-height: 1.7;
}

.tn-critical-email {
    display: flex;
    align-items: center;
    gap: 10px;

    color: #ff1f1f;

    font-size: 15px;
    font-weight: 600;
}
.tn-critical-email a {
  color: #ff3b3b;
}
/* ========================================
   RESPONSIVE
======================================== */

@media screen and (max-width: 1024px) {

    .tn-form-layout {
        grid-template-columns: 1fr;
    }
}

@media screen and (max-width: 768px) {

    .tn-form-grid {
        grid-template-columns: 1fr;
    }

    .tn-form-body {
        padding: 24px;
    }

    .tn-submit-btn {
        font-size: 16px;
    }

    .tn-response-card h3 {
        font-size: 24px;
    }
}
/* ========================================
   FIELD ERROR
======================================== */

.tn-error {
    margin-top: 8px;

    color: #e53935;

    font-size: 13px;
    font-weight: 600;
}

/* ========================================
   INVALID FIELD
======================================== */

.tn-field input.ng-invalid-field,
.tn-field select.ng-invalid-field,
.tn-field textarea.ng-invalid-field {
    border-color: #e53935;
    background: #fff8f8;
}

sp_widget.script:
(function() {
    data.side= $sp.getWidget('tracenow_sidebar');
    /* =====================================
       SUBMIT REQUEST
    ===================================== */

    if (input && input.action == "submit_support_request") {

        var gr = new GlideRecordSecure(
            "x_sysus_tracenow_support_request"
        );

        gr.initialize();

        gr.full_name = input.full_name;
        gr.email = input.email;
        gr.issue_type = input.issue_type;
        gr.priority = input.priority;
        gr.subject = input.subject;
        gr.description = input.description;

        gr.state = "new";

        var sysId = gr.insert();

        data.sys_id = sysId;

    }

})();
